internal final class UBSTriggerDimensionDefaulting  extends RunBaseBatch
{
    DataAreaId sourceEntity;
    AccountNum vendorAccount;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        sourceEntity,
        vendorAccount
    #endmacro

}

Method.Source:
    public boolean unpack(container packedClass)
    {
        Version version = runbase::getVersion(packedClass);
        switch (version)
        {
            case #CurrentVersion:
                [version, #CurrentList] = packedClass;
                break;
            default:
                return false;
        }

        return true;
    }

public DataAreaId parmSourceEntity(DataAreaId _sourceEntity = sourceEntity)
{
    sourceEntity = _sourceEntity;
    return sourceEntity;
}

public AccountNum parmVendorAccount(AccountNum _vendorAccount = vendorAccount)
{
    vendorAccount = _vendorAccount;
    return vendorAccount;
}

server static UBSTriggerDimensionDefaulting construct()
{
    return new UBSTriggerDimensionDefaulting();
}

    static void main(Args args)
    {
        UBSTriggerDimensionDefaulting import = UBSTriggerDimensionDefaulting::construct();

        if (import.prompt())
        {
            import.runOperation();
        }
    }

public void run()
{
    UBSTriggerDimensionDefaultingMain defaultDimension = new UBSTriggerDimensionDefaultingMain();
    defaultDimension.updateDefaultDimension(sourceEntity, vendorAccount);
}
